import { _OverlayTooltip as OverlayTooltip } from '@dynatrace/strato-components/charts';

import { useGeoLayerTooltip } from '../../hooks/use-geo-layer-tooltip.js';
import type { Location } from '../../types/location.js';
import type {
  DotLayerTooltipData,
  DotLayerTooltipHandler,
} from '../../types/tooltip.js';
import { isDefaultTooltipHandler } from '../../utils/tooltip-type-guards.js';

interface DotTooltipStatePayload {
  __color: string;
  __hoveredColor: string;
  __bearing: number;
  data: Location;
}

export interface DotLayerTooltipProps {
  tooltipTemplate?: DotLayerTooltipHandler;
  hidden?: boolean;
  symbolAlignment?: 'left' | 'right';
}

export const DotLayerTooltip = (props: DotLayerTooltipProps) => {
  const { tooltipTemplate, hidden, symbolAlignment } = props;

  const { data, inBounds, position } =
    useGeoLayerTooltip<DotTooltipStatePayload>('geoDot');

  if (hidden || !tooltipTemplate || !inBounds || !position) {
    return null;
  }

  if (!data || !data[0]) {
    return null;
  }

  const { __color: color, __bearing: bearing, data: customData } = data[0];
  const dotData: DotLayerTooltipData = {
    color,
    bearing,
    data: customData,
  };

  const template = tooltipTemplate(dotData);

  if (!template) {
    return null;
  }

  if (isDefaultTooltipHandler(tooltipTemplate)) {
    return template;
  }

  return (
    <OverlayTooltip
      legacyTemplate={template}
      symbolAlignment={symbolAlignment}
    />
  );
};

DotLayerTooltip['displayName'] = 'DotLayerTooltip';
